            elif val == move_best:
                # deterministic tie-break: smaller coordinate sum
                if (rx + ry) < (best_move[0] + best_move[1]):  # arbitrary stable tie
                    move_best = val
        if move_best > best_score:
            best_score = move_best
            best_move = (dx, dy)

    return [int(best_move[0]), int(best_move[1])]
